"""
MKT Original — Job chapters 39–41 (God's second speech + Behemoth/Leviathan)
Run: python3 scripts/zc-original-job-39-41.py

Ch39: God's animal gallery — divine mastery over wild creatures.
      Key terms: rĕʾēm (wild ox, v9), bĕhēmōt (beast, v15), sûs (horse, vv19-25),
      nēšer (eagle, v27), yĕʿēlê sālaʿ (mountain goats, v1), pereʾ (wild donkey, v5).
Ch40: God's challenge to Job + Behemoth.
      Key terms: hāpar mišpāṭ (discredit justice, v8), bĕhēmôt (Behemoth, v15),
      rĕʾîšît dĕrākāyw (first of his ways, v19), qāšeh gêwāh (binding the proud, v11-13).
Ch41: Leviathan — the chaos-monster.
      Key terms: liwyātān (Leviathan, v1), melek ʿal-kol-bĕnê-šāḥaṣ (king over the proud, v34),
      mî hiqdîm (who gave first, v11), ʾên ʿālāyw mōšēl (none rules over him, v33).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOB = {
  "39": {
    "1": "<p><span class='term'>Yādaʿtā ʿēt lèḏet yaʿălê-sālaʿ</span>: 'Do you know when the mountain goats give birth?' — <span class='term'>yĕʿēlê sālaʿ</span> (mountain goats of the rock): the ibex inhabiting inaccessible cliff terrain. <span class='term'>Yādaʿtā</span> is the divine interrogative formula deployed through this entire speech: a repeated assault on the limits of human knowledge. The animal-gallery speech answers Job's demand for a hearing with something unexpected: not legal defense but a tour of wild creation.</p>",
    "2": "<p><span class='term'>Tispōr yĕrāḥîm temallēʾnāh</span>: 'Can you count the months they carry young?' — <span class='term'>sāpar</span> (to count, number, keep record): the record-keeping that only the Creator maintains. <span class='term'>Yāḏaʿtā ʿēt liddtān</span>: 'do you know their time of birth?' — <span class='term'>ʿēt</span> (appointed time): the Creator knows the appointed time of every animal birth; Job does not.</p>",
    "3": "<p><span class='term'>Tikraʿnāh yĕladĕhennāh</span>: 'They crouch and deliver their young' — the birthing posture (<span class='term'>kāraʿ</span>, to kneel). <span class='term'>Ḥebĕlêhen yĕšallēḥnāh</span>: 'they are released from their birth-pangs' — <span class='term'>ḥēbel</span> (birth-pang, cord): the labor is completed and the pain released without human assistance.</p>",
    "4": "<p><span class='term'>Yiḥlĕṣû bĕnêhem yirbû babbār</span>: 'Their young thrive and grow in the open field' — <span class='term'>ḥālaṣ</span> (to be strong, thrive): independent maturation. <span class='term'>Yāṣĕʾû wĕlōʾ-šābû lāmmô</span>: 'they go out and do not return' — the complete independence: no mother's return, no human oversight. The wild creature is entirely outside the human economy.</p>",
    "5": "<p><span class='term'>Mî-šillaḥ pereʾ ḥopšî</span>: 'Who set the wild donkey free?' — <span class='term'>pereʾ</span> (wild donkey, onager): the paradigmatic wild animal (cf. 6:5; Gen 16:12). <span class='term'>Môsĕrôt ʾărôd mî pittēaḥ</span>: 'who opened the bonds of the onager?' — <span class='term'>ʾărôd</span> (onager, a species of wild ass): parallel term. The freedom of the wild ass is God's gift, not human concession.</p>",
    "6": "<p><span class='term'>ʾĂšer-śamtî ʿărābāh bêtô</span>: 'I have given the wilderness as its home' — <span class='term'>ʿărābāh</span> (steppe, desert, salt flats): the uninhabitable terrain that is nevertheless the wild donkey's natural home. The Creator designated a dwelling for the wild creature in the landscape humans cannot use.</p>",
    "7": "<p><span class='term'>Yiśḥaq lĕhamôn qiryāh</span>: 'It mocks the noise of the city' — the wild donkey's freedom manifested as contempt for human civilization and its constraints. <span class='term'>Tĕšûʾat nôgēś lōʾ yišmāʿ</span>: 'it does not hear the driver's shout' — <span class='term'>nôgēś</span> (taskmaster, driver): the creature that will not be pressed into service, unlike the domesticated donkey.</p>",
    "8": "<p><span class='term'>Yĕtûr hārîm mirʿēhû</span>: 'The mountain range is its pasture' — <span class='term'>tûr</span> (to range, explore): active foraging over vast territory. <span class='term'>Aḥar kol-yārôq yidĕrôš</span>: 'it searches out every bit of green' — the wild creature's self-sufficient foraging, needing no human farmer to provide for it.</p>",
    "9": "<p><span class='term'>Hăyōʾbeh rĕʾēm ʿābĕḏekā</span>: 'Will the wild ox agree to serve you?' — <span class='term'>rĕʾēm</span> (wild ox, aurochs): the great wild bovine, now extinct, ancestor of domesticated cattle. The LXX translates <span class='term'>monokeros</span> (unicorn), leading to centuries of confusion. The term refers to the mighty wild aurochs, utterly untameable. <span class='term'>ʾAbēḏekā</span> (your servant): the domestication-service that the wild ox refuses.</p>",
    "10": "<p><span class='term'>Hătiḵšōr rĕʾēm</span>: 'Can you harness the wild ox?' — <span class='term'>kāšar</span> (to bind, harness): the harnessing of a work-animal. <span class='term'>Yĕśaddēd ʿămāqîm ʾaḥărêkā</span>: 'will it follow you to break up the valley soil?' — the plowing-service that requires an obedient, domesticated animal. The wild ox cannot be directed to human agricultural ends.</p>",
    "11": "<p><span class='term'>Hătiḇṭaḥ bô kî-rab kōḥô</span>: 'Will you trust it because its strength is great?' — the irony: the wild ox has enormous power (<span class='term'>kōaḥ</span>) but none of it is usable for human purposes. <span class='term'>Wĕʿāzabtā ʾēlāyw yĕḡîʿekā</span>: 'will you leave your heavy work to it?' — <span class='term'>yĕḡîʿ</span> (labor, toil): the hardest agricultural tasks.</p>",
    "12": "<p><span class='term'>Hătaʾămîn bô kî-yāšûḇ zarʿekā</span>: 'Will you count on it to bring in your harvest?' — <span class='term'>ʾāman</span> (to trust): the trust that domesticated animals deserve but the wild ox does not. <span class='term'>Wĕgārnĕkā yĕʾassōp</span>: 'and gather it to your threshing floor?' — the threshing floor as the culmination of agricultural effort: the wild ox cannot be trusted to complete the cycle.</p>",
    "13": "<p><span class='term'>Kenap rĕnānîm neʿĕlāsāh</span>: 'Is the wing of the ostrich a joyful flapping?' — the ostrich-verse is textually difficult. <span class='term'>Rĕnānîm</span> (ostriches, or cries of joy): a plural used for ostriches from their cry. <span class='term'>ʾIm ʾeḇrāh ḥăsîḏāh wĕnōṣāh</span>: 'or the feathers of the stork?' — <span class='term'>ḥăsîḏāh</span> (stork/the loyal bird, from ḥeseḏ = steadfast love): the irony that the loyal-bird metaphor is here applied to the ostrich's apparently disloyal abandonment of eggs. MT text is uncertain.</p>",
    "14": "<p><span class='term'>Kî-taʿăzōḇ lāʾāreṣ bêṣêhā</span>: 'She abandons her eggs in the dirt' — <span class='term'>ʿāzaḇ</span> (to abandon, forsake): the same root used for divine abandonment in lament psalms. The ostrich's egg-abandonment is contrasted with the mountain goat's careful birth attendance (v1). Both are God's design.</p>",
    "15": "<p><span class='term'>Wattiškaḥ kî-regel tĕzûrāh</span>: 'Forgetting that a foot might trample them' — <span class='term'>šāḵaḥ</span> (to forget): the ostrich is characterized by forgetting. The apparent cruelty of the design — eggs left exposed to trampling — is the point: God made a creature that operates entirely outside the framework of protective care that humans value.</p>",
    "16": "<p><span class='term'>Hiqšîḥāh libânêhā lōʾ lāh</span>: 'She treats her chicks as if they are not hers' — <span class='term'>qāšāh</span> (to harden, make callous): the hardened indifference. <span class='term'>Rîq yĕḡîʿāh bĕlî-paḥaḏ</span>: 'her labor is for nothing, without anxiety' — no maternal anxiety, no concern for the investment. The ostrich's behavior is not cruel by design; it is outside the categories of care and cruelty.</p>",
    "17": "<p><span class='term'>Kî hišʾāh ʾĕlôah ḥāḵmāh</span>: 'For God has withheld wisdom from her' — <span class='term'>šāʾāh</span> (to withhold, neglect): the explicit divine explanation: God gave the ostrich no wisdom in this domain. <span class='term'>Wĕlōʾ-ḥālaq lāh babbînāh</span>: 'and given her no share of understanding' — the Creator distributed wisdom unevenly by design. Wisdom is not universal; its presence and absence in creatures is God's prerogative.</p>",
    "18": "<p><span class='term'>Kāʿēt tāmĕrîa harōmmāh tśaḥaq lassûs</span>: 'When she raises herself to run, she laughs at the horse' — the compensating gift: the ostrich that cannot fly and abandons her eggs runs faster than any horse. <span class='term'>ûlĕrōkĕḇô</span>: 'and its rider' — the creature without wisdom in one domain possesses extraordinary power in another. Each creature in God's gallery has its own specific excellence.</p>",
    "19": "<p><span class='term'>Hătittēn lassûs gĕḇûrāh</span>: 'Did you give the horse its might?' — <span class='term'>gĕḇûrāh</span> (might, strength, power): the same term used of divine power in psalms (Ps 21:14; 29:1). The war-horse is God's creature demonstrating divine power aesthetically. <span class='term'>Hălbiššô raʿmāh ṣawwāʾrô</span>: 'did you clothe its neck with a mane/thunder?' — <span class='term'>raʿmāh</span> (thunder, or mane — the term is disputed): the neck of the war-horse is clothed with what shakes like thunder.</p>",
    "20": "<p><span class='term'>Hatarzeʾennû kāʾarḇeh</span>: 'Can you make it spring/leap like a locust?' — <span class='term'>rāzaʿ</span> (to cause to leap, shudder): the locust-comparison for the horse's spring. <span class='term'>Hôḏ naḥrô ʾêmāh</span>: 'the majesty of its snorting is terrifying' — <span class='term'>hôḏ</span> (majesty, splendor): the divine-attribute term applied to the horse's snort. The horse embodies in animal form the attributes of divine power.</p>",
    "21": "<p><span class='term'>Yaḥpĕrû bāʾēmeq wayyāśîś bĕḵōaḥ</span>: 'It paws the valley and surges forward in strength' — <span class='term'>ḥāpar</span> (to dig, paw the ground): the pre-charge preparation. <span class='term'>Yēṣēʾ liqraʾt-nāšeq</span>: 'it charges into the battle' — the battle-vocabulary: the horse is a purpose-built creation for warfare, going out (<span class='term'>yāṣāʾ</span>) to meet armed conflict.</p>",
    "22": "<p><span class='term'>Yiśḥaq lĕpaḥaḏ wĕlōʾ yēḥāt</span>: 'It laughs at fear and is not alarmed' — <span class='term'>śāḥaq</span> (to laugh): the horse's fearlessness expressed as laughter at what frightens others. <span class='term'>Wĕlōʾ-yāšûḇ mipnê-ḥāreb</span>: 'it does not turn back from the sword' — the charge that does not retreat. Courage as a designed animal characteristic.</p>",
    "23": "<p><span class='term'>ʿālāyw tirtaqqeš ʾašpāh</span>: 'The quiver rattles on its flank' — the horse carries the archer's equipment. <span class='term'>Lahab ḥănît ûkîḏôn</span>: 'the flashing spear and javelin' — <span class='term'>lahab</span> (flame, flash): the weapons' glint in battle. The full military array.</p>",
    "24": "<p><span class='term'>Bĕrāgaz wĕraʿaš yĕgammaʾ-ʾāreṣ</span>: 'With fierce excitement it devours the ground' — <span class='term'>rāgaz</span> (to tremble, be excited): the horse's physical agitation before battle. <span class='term'>Wĕlōʾ-yaʾămin kî-qôl šôpār</span>: 'at the sound of the trumpet it cannot stand still' — the trumpet (<span class='term'>šôpār</span>) triggers uncontrollable movement. The horse is designed for battle as surely as the eagle for soaring.</p>",
    "25": "<p><span class='term'>Bĕdê šôpār yōmar heʾāḥ</span>: 'At the trumpet blast it cries Aha!' — the horse's battle-cry, <span class='term'>heʾāḥ</span>: the triumph sound. <span class='term'>Yārîaḥ milḥāmāh mērāḥôq</span>: 'it scents the battle from far away' — the combat-sense as a designed organ. <span class='term'>Raʿam śārîm ûtĕrûʿāh</span>: 'the thunder of commanders and the battle cry' — the horse responds to all of these with increasing excitement, not retreat.</p>",
    "26": "<p><span class='term'>Hămibbiynāṯĕkā yaʾbēr nēṣ</span>: 'Does the hawk soar by your wisdom?' — <span class='term'>nēṣ</span> (hawk, falcon): the migratory raptor. <span class='term'>Yiprōś kĕnāpāyw lĕtêmān</span>: 'does it spread its wings toward the south?' — the migratory instinct, the seasonal southward flight: no human programmed this. The hawk's migration is God's design, not human wisdom.</p>",
    "27": "<p><span class='term'>ʾIm-ʿal-pîkā yiḡbah nāšer</span>: 'Does the eagle soar at your command?' — <span class='term'>nāšer</span> (eagle, griffon vulture): the great soaring raptor. <span class='term'>Wĕḵî yārîm qinnô</span>: 'does it build its nest on the heights?' — the nest-placement on inaccessible heights: not human instruction but divine endowment.</p>",
    "28": "<p><span class='term'>Sālaʿ yiškon wĕyitlônān</span>: 'It lives and stays on the cliff' — <span class='term'>sālaʿ</span> (cliff, crag): the eagle's chosen dwelling. <span class='term'>ʿal-šen-seleʿ ûmĕṣûḏāh</span>: 'on the rocky crag and the natural stronghold' — <span class='term'>mĕṣûḏāh</span> (fortress, stronghold): God placed the eagle's home in the equivalent of a natural fortification.</p>",
    "29": "<p><span class='term'>Miššam yāpîr-ʾōḵel</span>: 'From there it watches for food' — <span class='term'>ṣāpar</span> (to look out): the eagle's survey-vision from its height-advantage. <span class='term'>Lĕmērāḥôq ʿênāyw yabbîṭû</span>: 'its eyes spot prey from far away' — the eagle's visual acuity as a God-designed tool. The animal gallery ends with a creature that exemplifies both transcendence (height) and precision (sight).</p>",
    "30": "<p><span class='term'>ûpĕrāḥāyw yĕʿalĕṭû-ḏām</span>: 'Its young ones drink blood' — the eagle chick nourished on prey-blood. <span class='term'>ûbăʾăšer ḥălālîm šām hûʾ</span>: 'where the slain are, there the eagle is' — quoted in Matt 24:28 / Luke 17:37 by Jesus: 'where the corpse is, there the eagles will gather.' The eagle as nature's end-of-life functionary, designed to recycle the dead. The divine provision for death is part of the created order.</p>"
  },
  "40": {
    "1": "<p>The brief narrative marker between the animal gallery and God's direct challenge to Job — <span class='term'>wayyaʿan YHWH ʾet-ʾiyyôḇ wayyōʾmer</span>: the LORD speaks again, directly addressing Job.</p>",
    "2": "<p><span class='term'>Hăroḇ ʿim-šadday yissōr</span>: 'Will a critic argue with the Almighty?' — <span class='term'>rîḇ</span> (to contend, take legal action): the lawsuit-term. <span class='term'>Môkîaḥ ʾĕlôah yaʿănenāh</span>: 'let the one who accuses God answer' — <span class='term'>môkîaḥ</span> (the one who reproves, the accuser-plaintiff): Job took on the role of reprover; now he must answer. The challenge is not hostile but genuine: God takes Job's lawsuit seriously enough to invite a response.</p>",
    "3": "<p>The narrative marker for Job's first response: <span class='term'>wayyaʿan ʾiyyôḇ ʾet-YHWH wayyōʾmer</span>. Job's response is remarkably brief — 2 verses of capitulation — compared to the lengthy speeches that preceded it.</p>",
    "4": "<p><span class='term'>Qallōtî māh ʾăšîḇekā</span>: 'I am of little account; what shall I say to you?' — <span class='term'>qālal</span> (to be small, of little account): the self-assessment that reverses Job's earlier confident demand. <span class='term'>Yādî śamtî lĕpî</span>: 'I put my hand over my mouth' — the silence-gesture of one who has heard enough to know he cannot argue further. The very gesture Job refused to make before the divine voice silences him.</p>",
    "5": "<p><span class='term'>ʾAḥat dibbartî wĕlōʾ ʾešneh</span>: 'I spoke once but will not answer again' — the numbered renunciation: once + twice. <span class='term'>Ûštayim wĕlōʾ ʾôsîp</span>: 'twice, but I will add nothing more' — the finality. Job does not recant his claims of innocence; he simply falls silent before the divine voice. This is response without refutation.</p>",
    "6": "<p>The second divine speech opens with the same theophanic formula as 38:1: <span class='term'>YHWH ʾet-ʾiyyôḇ miṣ-śĕʿārāh</span> — from the storm. The continued storm-setting grounds both speeches in the same sustained divine encounter.</p>",
    "7": "<p><span class='term'>ʾĔzār-nāʾ kĕgeber ḥălāṣêkā</span>: 'Brace yourself like a man/warrior' — the same challenge as 38:3. <span class='term'>ʾEšʾālĕkā wĕhôḏîʿēnî</span>: 'I will question you, and you will answer me' — God is not done; the second speech intensifies the challenge by moving from creation to justice.</p>",
    "8": "<p><span class='term'>ʾAp tāper mišpāṭî</span>: 'Would you discredit/nullify my justice?' — <span class='term'>pārar</span> (to break, nullify, frustrate): would Job break apart the divine justice-system? <span class='term'>Tĕrišʿēnî lĕmaʿan tiṣdāq</span>: 'would you condemn me so that you can be righteous?' — the zero-sum framing: for Job to be righteous, would God have to be guilty? The question cuts to the heart of Job's dilemma — and the answer the whole book gives is: No. Both can be vindicated.</p>",
    "9": "<p><span class='term'>Wĕʾim-zĕrôaʿ kĕʾēl lāk</span>: 'Do you have an arm like God?' — <span class='term'>zĕrôaʿ</span> (arm, strength): the arm as symbol of royal power. <span class='term'>ûḇĕqôl kāmōhû tarʿēm</span>: 'can you thunder with a voice like his?' — the theophanic voice of thunder as divine speech-power (cf. Ps 29). These are not taunts but genuine tests of what would be required for Job to administer justice himself.</p>",
    "10": "<p><span class='term'>ʿĂḏeh-nāʾ gāʾôn wāgōḇah</span>: 'Adorn yourself with majesty and height' — <span class='term'>gāʾôn</span> (majesty, pride): the same term used for divine majesty (Ps 93:1) and dangerous human pride. <span class='term'>Wĕhôḏ wĕhāḏār tilbaš</span>: 'dress yourself in glory and splendor' — <span class='term'>hôḏ wĕhāḏār</span>: the divine-attribute pair of honor + majesty (Ps 96:6). God invites Job to try on the divine attributes.</p>",
    "11": "<p><span class='term'>Hăpeṣ ʿeḇrôt ʾappekā</span>: 'Let out the fury of your wrath' — <span class='term'>ʿeḇrāh</span> (fury, overflow of wrath): the cascading divine anger. <span class='term'>ûrĕʾēh kol-gēʾeh wĕhašpîlēhû</span>: 'look at everyone proud and humble him' — the administration of retributive justice God is inviting Job to attempt. If Job can do it, he wins. The point: no one can.</p>",
    "12": "<p><span class='term'>Rĕʾēh kol-gēʾeh haknaʿĕhû</span>: 'Look at every proud person and bring him low' — the comprehensive justice Job has demanded. <span class='term'>ûhădōk rĕšāʿîm taḥtām</span>: 'tread down the wicked where they stand' — the punishment of wickedness in-place, immediate, comprehensive. This is what human justice cannot do.</p>",
    "13": "<p><span class='term'>Ṭomĕnēm bĕʿāpār yaḥad</span>: 'Thrust them into the dust together' — the mass entombment of the wicked. <span class='term'>Pĕnêhem ḥăboš bammistār</span>: 'bind their faces in the realm of concealment' — <span class='term'>mistār</span> (hidden place, concealment): the hidden underworld. The challenge: can Job actually accomplish the cosmic moral administration he has demanded of God?</p>",
    "14": "<p><span class='term'>Wĕgam-ʾănî ʾôḏeh lāk</span>: 'Then I myself will acknowledge you' — <span class='term'>yāḏāh</span> (to praise, acknowledge): God's own confession of praise if Job can do it. <span class='term'>Kî-tôšîaʿ yĕmînĕkā lāk</span>: 'that your own right hand can save you' — the condition of self-sufficiency: if Job has such power, he needs no one. The point is that he does not and cannot. The right hand that saves is YHWH's (Ps 98:1; Isa 63:5).</p>",
    "15": "<p><span class='term'>Rĕʾēh-nāʾ bĕhēmôt ʾăšer-ʿāśîtî ʿimmāk</span>: 'Look at Behemoth, which I made just as I made you' — <span class='term'>bĕhēmôt</span>: plural of intensity from <span class='term'>bĕhēmāh</span> (beast, animal) — the super-beast. The identification is debated (hippopotamus most likely; others suggest a mythological creature). <span class='term'>ʿĀśîtî ʿimmāk</span>: 'I made alongside you' — Job and Behemoth are fellow-creatures of the same Creator.</p>",
    "16": "<p><span class='term'>Hinnēh nāʾ kōḥô bĕmotnāyw</span>: 'Look at the strength in his haunches' — the anatomical survey of Behemoth's power. <span class='term'>Wĕʾônô bišrîrê biṭnô</span>: 'the power in the muscles of his belly' — <span class='term'>ʾôn</span> (strength, virility): the term for reproductive and physical potency. Behemoth's power is fundamentally bodily, concentrated in its core.</p>",
    "17": "<p><span class='term'>Yāpōẑ zĕnāḇô kĕʾārez</span>: 'He swings his tail like a cedar' — the tail-comparison to a cedar tree suggests the large, powerful tail of a hippopotamus (not the stubby tail of an elephant, making 'elephant' identification less likely). <span class='term'>Gîdê pāḥadāyw yĕśôrāgû</span>: 'the sinews of his thighs are tightly woven' — the anatomical detail of the powerful thigh-muscles.</p>",
    "18": "<p><span class='term'>ʿAṣāmāyw ʾăpîqê nĕḥūšāh</span>: 'His bones are like bronze pipes' — the mineral comparison for bone-density. <span class='term'>Gĕrāmāyw kĕmôṭ barzel</span>: 'his limbs are like bars of iron' — the dual mineral comparison (bronze/iron) establishes Behemoth's structural invulnerability to normal force.</p>",
    "19": "<p><span class='term'>Hûʾ rĕʾîšît darkê-ʾēl</span>: 'He ranks first among God's works' — <span class='term'>rĕʾîšît</span> (first, chief): Behemoth as the premier example of divine creative power in the animal realm. <span class='term'>Hāʿōśô yaggaš ḥarbô</span>: 'only his Maker can approach him with a sword' — the exclusive divine prerogative over Behemoth. No human can subdue him; only God can.</p>",
    "20": "<p><span class='term'>Kî-yĕḇûl hārîm yiśśĕʾû-lô</span>: 'The mountains produce food for him' — the scale of Behemoth's provisioning: mountains supply his diet. <span class='term'>Kol-ḥayyat haśśāḏeh yĕśaḥăqû-šām</span>: 'all the wild beasts play around him' — the paradox: the most powerful creature is surrounded by smaller animals that play near him without fear.</p>",
    "21": "<p><span class='term'>Taḥat ṣeʾĕlîm yiškāḇ</span>: 'He rests beneath the lotus plants' — <span class='term'>ṣeʾĕlîm</span> (lotus plants, or perhaps a tree): the shade-vegetation of the Nile delta or Jordan valley, consistent with hippopotamus habitat. <span class='term'>Bĕsēter qāneh ûḇiṣṣāh</span>: 'sheltered in the reeds and swamps' — the marshy habitat of the hippo.</p>",
    "22": "<p><span class='term'>Yĕsukuhû ṣillālîm ṣalmāwet</span>: 'The trees shade him with deep shadow' — <span class='term'>ṣalmāwet</span> (deep shadow, shadow of death): the word usually translated 'valley of the shadow of death' (Ps 23:4) here describes Behemoth's shade-canopy. <span class='term'>ʿArĕḇê-naḥal yisabbĕḇûhû</span>: 'willows of the brook encircle him' — the botanical precision of the riparian habitat.</p>",
    "23": "<p><span class='term'>Hēn yaʿăšōq nāhār lōʾ yaḥpôz</span>: 'Even if the river floods, Behemoth is untroubled' — <span class='term'>ʿāšaq</span> (to oppress, overwhelm): flood-force does not move him. <span class='term'>Yiḇṭaḥ kî-yāgîaḥ yardēn</span>: 'he is at ease though the Jordan rushes into his mouth' — the Jordan at flood-force is merely a drink for Behemoth. The cosmic confidence of a creature designed for power in water.</p>",
    "24": "<p><span class='term'>Bĕʿênāyw yiqqāḥennû</span>: 'Can anyone catch him while he watches?' — the rhetorical answer is no. <span class='term'>Bĕmôqĕšîm yinnaq-ʾāp</span>: 'can anyone trap him by piercing his nose?' — the standard animal-capture technique (nose-ring/rope): impossible with Behemoth. He cannot be mastered.</p>"
  },
  "41": {
    "1": "<p><span class='term'>Timšōk liwyātān bĕḥakkāh</span>: 'Can you pull up Leviathan with a hook?' — <span class='term'>liwyātān</span> (Leviathan): the great sea-serpent/dragon. The name likely derives from <span class='term'>lāwāh</span> (to coil/twine) + the augmented form. In Ugaritic mythology, Leviathan (ltn) is the seven-headed sea-dragon defeated by Baal. The OT uses the figure variably: as a literal creature (here and Ps 104:26) and as a mythological chaos-symbol (Isa 27:1; Ps 74:14). God's ownership of Leviathan is the theological point. <span class='term'>Ûḇĕḥeḇel tišqîaʿ lĕšônô</span>: 'or hold down his tongue with a rope?' — capture is impossible.</p>",
    "2": "<p><span class='term'>Hăḵĕrōm tāšîm bĕʾappô</span>: 'Can you put a rush through his nose?' — <span class='term'>ʾagmôn</span> (rush, reed): the material for a nose-ring. The nose-ring/hook was the standard device for controlling large animals. <span class='term'>Ûḇĕḥôaḥ tiṭqoḇ laḥyô</span>: 'or run a hook through his jaw?' — the jaw-hook: equally impossible. Neither instrument of animal mastery works on Leviathan.</p>",
    "3": "<p><span class='term'>Hăyarbeh ʾēlêkā taḥănûnîm</span>: 'Will he beg you for mercy?' — <span class='term'>taḥănûnîm</span> (pleas for favor/mercy): the petitioner's vocabulary. The absurdity: Leviathan as suppliant before a human. <span class='term'>Ûyĕdabbēr ʾēlêkā rakkôt</span>: 'will he address you with soft words?' — <span class='term'>rāk</span> (soft, gentle): the opposite of the harsh words he actually produces. Leviathan does not plead; he threatens.</p>",
    "4": "<p><span class='term'>Hăyikrōt bĕrît ʾittāk</span>: 'Will he make a covenant with you?' — <span class='term'>kārat bĕrît</span> (to cut a covenant): the covenant-making formula. Leviathan cannot be treaty-bound. <span class='term'>Tiqāḥennû leʿeḇed ʿôlām</span>: 'will you bind him as your permanent slave?' — <span class='term'>leʿeḇed ʿôlām</span> (permanent slave): the deepest category of servitude. Impossible with Leviathan.</p>",
    "5": "<p><span class='term'>Hătĕśaḥeq-bô kĕṣippôr</span>: 'Will you play with him like a bird?' — the diminutive comparison: a pet bird vs. Leviathan. <span class='term'>Ûtiqqĕšennû lĕnaʿărôtêkā</span>: 'will you leash him for your young women?' — the domestication-play imagery. The absurdity drives home the point: no human treats Leviathan as a pet.</p>",
    "6": "<p><span class='term'>Yikrû ʿālāyw ḥabbārîm</span>: 'Will trading partners negotiate for him?' — <span class='term'>ḥabbār</span> (partner, associate): the commercial-partner term. Leviathan cannot be commodified or traded. <span class='term'>Yĕḥaṣṣûhû bên kĕnaʿănîm</span>: 'will merchants distribute him among buyers?' — the Phoenician trading network (<span class='term'>kĕnaʿĕnîm</span> = Canaanites = traders) cannot handle Leviathan as merchandise.</p>",
    "7": "<p><span class='term'>Hătĕmallēʾ bĕśukkôt ʿôrô</span>: 'Can you fill his skin with harpoons?' — <span class='term'>sukkāh</span> (here: harpoon/barbed spear — specialized fishing equipment): the instruments of large-game marine hunting. <span class='term'>ûḇĕṣaltĕʾselê dāgāh rōʾšô</span>: 'or his head with fishing lances?' — the futility of applying normal hunting tools to Leviathan.</p>",
    "8": "<p><span class='term'>Śîm-ʿālāyw kappekā</span>: 'Lay your hand on him' — the imperative of attempted contact. <span class='term'>Tizkōr milḥāmāh ʾal-tôsep</span>: 'you will remember the encounter and never try again' — a single touch will be sufficient to teach permanent respect. The experiential knowledge of Leviathan cannot be acquired a second time.</p>",
    "9": "<p><span class='term'>Hēn tôḥaltô niḵzāḇāh</span>: 'Any hope of mastering him is an illusion' — <span class='term'>niḵzāḇāh</span> (is proved false/deceptive): the hope of subduing Leviathan is inherently false hope. <span class='term'>ʾAp-ʾel-marʾāyô yulāl</span>: 'even the sight of him knocks a man down' — not the encounter but merely the sight produces collapse. Leviathan overwhelms by appearance alone.</p>",
    "10": "<p><span class='term'>Lōʾ-ʾakzār kî yĕʿûrennû</span>: 'No one is fierce enough to rouse him' — <span class='term'>ʾakzār</span> (fierce, ruthless): the quality required to provoke Leviathan. <span class='term'>ûmî hûʾ lĕpānay yitʿaṣṣāḇ</span>: 'who then is able to stand before me?' — the pivot: if no one dares rouse Leviathan, who dares stand before the Creator of Leviathan? The rhetorical question moves from creature to Creator.</p>",
    "11": "<p><span class='term'>Mî hiqdîm-lî waʾăšallēm</span>: 'Who has given to me first, that I should owe him in return?' — <span class='term'>hiqḏîm</span> (to anticipate, go before, give first): the claim that God owes anything to a creature because the creature acted first. Paul quotes this in Rom 11:35. <span class='term'>Taḥat kol-haššāmayim lî-hûʾ</span>: 'everything under all the heavens belongs to me' — the absolute sovereignty statement that makes obligation to a creature logically impossible. No creature can place God in its debt.</p>",
    "12": "<p><span class='term'>Lōʾ-ʾaḥărîš baḏāyw</span>: 'I will not be silent about his structure/limbs' — <span class='term'>baḏ</span> (limb, part, branch): Leviathan's anatomical components will be narrated. <span class='term'>ûḏbar gĕḇûrôt ûḥîn ʿerkô</span>: 'his power and the grace of his proportion' — <span class='term'>ḥîn ʿerkô</span> (the grace/beauty of his arrangement): Leviathan is described as beautiful. The chaos-creature has aesthetic excellence.</p>",
    "13": "<p><span class='term'>Mî-gillāh pĕnê lĕḇûšô</span>: 'Who can remove the outer layer of his skin?' — <span class='term'>lĕḇûš</span> (garment, outer layer): the skin as clothing. <span class='term'>Bĕḵepal rissĕnô mî yāḇôʾ</span>: 'who can break through his double layer of defense?' — <span class='term'>riśsôn</span> (bridle, bit — here: the double armor): the overlapping armor-like skin of the crocodilian.</p>",
    "14": "<p><span class='term'>Daltê pānāyw mî pātāḥ</span>: 'Who can pry open the doors of his mouth?' — the jaws as locked doors. <span class='term'>Sĕḇîḇôt šinnāyw ʾêmāh</span>: 'his teeth are ringed with dread' — <span class='term'>šinnāyw</span> (teeth): surrounding each tooth is <span class='term'>ʾêmāh</span> (dread, terror): the teeth themselves inspire terror.</p>",
    "15": "<p><span class='term'>Gāʾăwāh ʾăpîqê māginnîm</span>: 'His back is like rows of shields' — the scale-armor described as military shields in formation. <span class='term'>Sāgûr ḥôtām ṣar</span>: 'locked together like a tight seal' — <span class='term'>ḥôtām</span> (seal, signet): the scales fit as tightly as a seal impression, leaving no gap.</p>",
    "16": "<p><span class='term'>ʾEḥāḏ bĕʾeḥāḏ yiggāšû</span>: 'Each one pressed so close to the next' — the interlocking precision of the scales. <span class='term'>Wĕrûaḥ lōʾ-yāḇôʾ bênêhem</span>: 'no breath of air passes between them' — the absolute seal of Leviathan's armor: not even air can penetrate. The most complete defensive structure in creation.</p>",
    "17": "<p><span class='term'>ʾîš bĕʾāḥîw yĕdubāqû</span>: 'They cling together one to another' — the scales described as companions clinging. <span class='term'>Yitlapĕtû wĕlōʾ yitpārāḏû</span>: 'they lock onto each other and will not separate' — <span class='term'>lāpaṯ</span> (to grasp, seize): the scales' mutual grip is permanent.</p>",
    "18": "<p><span class='term'>ʿAṭîšōtāyw ʾôr tĕhallel</span>: 'His sneezes flash light' — the dragon's fire-breathing described through the sneeze. <span class='term'>Wĕʿênāyw kĕʿapʿappê šāḥar</span>: 'his eyes shine like the gleam of dawn' — <span class='term'>šāḥar</span> (dawn): the eyelids of dawn as the comparison for Leviathan's eyes. Both fire and light: the creature embodies elemental power aesthetically.</p>",
    "19": "<p><span class='term'>Millĕpîw lappîḏîm yahalōkû</span>: 'Burning torches go from his mouth' — the fire-breathing imagery. <span class='term'>Kîḏôḏê ʾēš yimlāṭû</span>: 'sparks of fire fly out' — <span class='term'>kîḏôḏ</span> (spark): the sparks of Leviathan's breath. The chaos-creature as a fire-elemental.</p>",
    "20": "<p><span class='term'>Minnĕḥîrāyw yēṣēʾ ʿāšān</span>: 'Smoke billows from his nostrils' — the nostrils as smoke-vents. <span class='term'>Kĕdûḏ nāpûaḥ wĕʾagmôn</span>: 'like a boiling pot over burning rushes' — the domestic cooking-fire comparison: the world's most fearsome creature compared to a kitchen pot, but the quantity and heat are Leviathan's.</p>",
    "21": "<p><span class='term'>Napšô geḥālîm tĕlahaṭ</span>: 'His breath sets coals afire' — <span class='term'>nepeš</span> (breath, soul, life): the breath as the source of fire. <span class='term'>Wĕlahab mippiyw yēṣēʾ</span>: 'a flame shoots out of his mouth' — the comprehensive fire-generation: both breath-heat and visible flame. The chaos-creature as lord of fire.</p>",
    "22": "<p><span class='term'>Bĕṣawwāʾrô yālîn ʿōz</span>: 'Strength resides in his neck' — the neck as the seat of power. <span class='term'>Wĕlĕpānāyw tādûṣ dĕʾābāh</span>: 'dismay dances before him' — <span class='term'>dĕʾābāh</span> (dismay, sorrow, despair) as Leviathan's advance-companion. Terror precedes his movement.</p>",
    "23": "<p><span class='term'>Mapĕlê bĕśārô ḏāḇĕqû</span>: 'The layers of his flesh are locked together' — <span class='term'>dāḇēq</span> (to cling, stick): the flesh as armored as the scales. <span class='term'>Yāṣûq ʿālāyw bal-yimmôṭ</span>: 'hard on him and immovable' — cast (<span class='term'>yāṣaq</span>) solid, not movable. The anatomical description emphasizes the invulnerability of every layer.</p>",
    "24": "<p><span class='term'>Libbô yāṣûq kĕmo-ʾāben</span>: 'His heart is like cast stone' — the heart as the deepest/innermost layer: also cast solid. <span class='term'>Wĕyāṣûq kĕpeleḥ taḥtît</span>: 'as hard as the lower millstone' — the lower millstone (the fixed stone, not the rotating one): the hardest, most fixed stone in common experience. Leviathan's heart is the most interior expression of his invulnerability.</p>",
    "25": "<p><span class='term'>Mĕśāw yāgûrû ʾêlîm</span>: 'When he rears up, the mighty are terrified' — <span class='term'>ʾêl</span> (strong man, mighty one): even the powerful fear Leviathan's rising. <span class='term'>Miššĕḇārîm yiṯḥaṭṭāʾû</span>: 'they fall back before his thrashing' — <span class='term'>šāḇar</span> (waves, or here: thrashings): the waves/chaos-motions of Leviathan cause retreat.</p>",
    "26": "<p><span class='term'>Massîgēhû ḥereḇ bal-tāqûm</span>: 'The sword that reaches him cannot hold' — every weapon fails against Leviathan's armor. <span class='term'>Ḥănît wĕdarda ûširyāh</span>: 'spear, dart, and javelin' — the full inventory of ancient ranged weapons: all useless.</p>",
    "27": "<p><span class='term'>Yaḥšōḇ lĕṯeḇen barzel</span>: 'He regards iron as straw' — the invulnerability scale: iron is straw, bronze is rotten wood. <span class='term'>Wĕnĕḥūšāh kĕʿēṣ rāqāḇ</span>: 'bronze is like rotten wood' — the materials of weapon-making are worthless against Leviathan. The standard military materials fail completely.</p>",
    "28": "<p><span class='term'>Lōʾ-yabriḥennû ben-qāšeṯ</span>: 'The arrow cannot make him flee' — <span class='term'>ben-qāšeṯ</span> (son of the bow/arrow): poetic for the arrow. <span class='term'>Lĕqaš nehpĕḵû-lô ʾabnê-qālaʿ</span>: 'sling stones become chaff to him' — sling stones, which could kill Goliath (1 Sam 17:49), are meaningless against Leviathan.</p>",
    "29": "<p><span class='term'>Kĕqaš neḥšĕḇû tôṭāḥ</span>: 'He regards war clubs as straw' — the close-combat weapons are as useless as the ranged ones. <span class='term'>Wayiśḥaq lĕraaš kîḏôn</span>: 'he laughs at the shaking of a lance' — <span class='term'>śāḥaq</span> (to laugh): the laughter motif appears again, now applied to Leviathan laughing at human weapons, as the horse laughed at fear (39:22).</p>",
    "30": "<p><span class='term'>Taḥtāyw ḥaddûḏê ḥereś</span>: 'His underbelly is like sharp pottery shards' — the only potentially vulnerable surface (the belly) is itself sharpened. <span class='term'>Yirpaḏ ḥārûṣ ʿălê-ṭîṭ</span>: 'he plows jagged furrows through the mud' — Leviathan's passage itself creates destruction. His belly weapon-izes the ground.</p>",
    "31": "<p><span class='term'>Yaṯrîaḥ kaṣṣîr mĕṣûlāh</span>: 'He makes the depths churn like a boiling pot' — <span class='term'>mĕṣûlāh</span> (depth, abyss): the deep sea becomes a boiling pot under Leviathan's movement. <span class='term'>Wĕyāśem kayĕrôqāḥ</span>: 'he churns the sea like a jar of perfume' — the sea reduced to a stirred cosmetic jar. Leviathan's power expressed through domestic compression.</p>",
    "32": "<p><span class='term'>ʾAḥărāyw yaʾîr nātîḇ</span>: 'A glistening path shines behind him' — the phosphorescent wake of Leviathan's movement. <span class='term'>Yaḥšōḇ tĕhôm lĕśêḇāh</span>: 'one would think the sea had turned white' — the abyss (<span class='term'>tĕhôm</span>, the deep of Gen 1:2) appears white-haired behind Leviathan's wake. The deep itself appears to age in his presence.</p>",
    "33": "<p><span class='term'>ʾên ʿălāyw mōšēl</span>: 'There is nothing on earth to compare with him' — <span class='term'>māšal</span> (to rule, to compare): no earthly creature masters Leviathan or serves as his comparison. <span class='term'>ʿĀśûy lĕḇĕlî-ḥāt</span>: 'he is fashioned without fear' — <span class='term'>bĕlî-ḥāt</span> (without fear): fearlessness built into his design. The creature who inspires fear in everything else was made without fear himself.</p>",
    "34": "<p><span class='term'>Kol-gāḇōah yirʾeh</span>: 'He surveys everything that exalts itself' — Leviathan as the surveyor-king of the proud. <span class='term'>Hûʾ melek ʿal-kol-bĕnê-šāḥaṣ</span>: 'he is king over all the proud' — <span class='term'>bĕnê šāḥaṣ</span> (children of pride/arrogance): the proud and haughty are Leviathan's subjects. The chaos-monster who cannot be tamed by any human king is himself king of everything that exalts itself. The implication: Job's proud demand for a legal confrontation with God placed him in Leviathan's realm. The God who made and masters Leviathan is the one Job was challenging.</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'job')
    merge_comm(c, JOB)
    save_comm('mkt-original', 'job', c)
    total = sum(len(v) for v in JOB.values())
    print(f'job mkt-original: wrote {total} verses across ch 39-41')

if __name__ == '__main__':
    main()
